  "type": "FLIP_CARD",
  "lessonText": "Understanding game loops is crucial for creating dynamic and responsive games.",
  "data": {
    "cards": [
      {
        "front": "What is a game loop?",
        "back": "A game loop is a cycle that continuously runs during the gameplay, managing game state updates and rendering.",
        "icon": "loop"
      },
      {
        "front": "Why are game loops important?",
        "back": "They ensure smooth gameplay by controlling the frame rate and managing game logic.",
        "icon": "importance"
      },
      {
        "front": "What are the main components of a game loop?",
        "back": "The main components include initialization, update, render, and cleanup.",
        "icon": "components"
      },
      {
        "front": "How do you implement a basic game loop in Python?",
        "back": "You can use a while loop that calls update and render functions repeatedly until a quit condition is met.",
        "icon": "implementation"
      }
    ]
  }
}
